import json
from adk import ToolResponse

def validate_chunk_schema(tool_response: ToolResponse):
    expected_schema = {
        'type': 'array',
        'items': {
            'type': 'object',
            'properties': {
                'content': {'type': 'string'},
                'metadata': {'type': 'object'},
                'embedding': {'type': 'array'}
            }
        }
    }

    try:
        chunks = json.loads(tool_response.content)
        if not all(isinstance(c, dict) and 'content' in c for c in chunks):
            VexMonitor.log_error('CHUNK_FORMAT_INVALID', {'sample': chunks[:2]})
            return False
    except json.JSONDecodeError:
        VexMonitor.log_error('CHUNK_JSON_MALFORMED')
        return False
    return True

from datetime import datetime, timedelta

def check_embedding_staleness(session_state):
    embeddings = session_state.get('document_embeddings', {})
    now = datetime.utcnow()

    stale_count = 0
    for emb_id, emb_data in embeddings.items():
        created_at = datetime.fromisoformat(emb_data['created_at'])
        if now - created_at > timedelta(hours=2):
            stale_count += 1
            VexMonitor.log_warning('EMBEDDING_STALE', {'id': emb_id, 'age_hours': (now - created_at).total_seconds() / 3600})

    if stale_count / len(embeddings) > 0.3:
        VexMonitor.log_alert('SESSION_STALENESS_HIGH', {'stale_ratio': stale_count / len(embeddings)})

