from adk import SessionStateManager

class SmartCacheManager(SessionStateManager):
    def get_embeddings(self, doc_ids: list[str]):
        cache = self.session.get('embeddings_cache', {})
        fresh_embeddings = []

        for doc_id in doc_ids:
            cached = cache.get(doc_id)
            if self._is_fresh(cached):
                fresh_embeddings.append(cached['embedding'])
            else:
                # Refresh stale embedding
                doc_content = self.vector_store.get(doc_id)
                new_emb = self.embedder.embed([doc_content])[0]
                cache[doc_id] = {
                    'embedding': new_emb,
                    'created_at': datetime.utcnow().isoformat(),
                    'doc_id': doc_id
                }
                fresh_embeddings.append(new_emb)

        self.session['embeddings_cache'] = cache
        return fresh_embeddings

    def _is_fresh(self, cached):
        if not cached:
            return False
        age = datetime.utcnow() - datetime.fromisoformat(cached['created_at'])
        return age < timedelta(hours=1)

