from adk import before_agent_callback
from vex_sdk import Vex

@vex.init(installation_id="your-vex-id")
@before_agent_callback
def vex_rag_monitor(ctx):
    # Auto-detect RAG patterns in ADK agents
    if 'retrieved_docs' in ctx.context:
        vex.track_retrieval_quality(
            query=ctx.context['query'],
            retrieved_docs=ctx.context['retrieved_docs'],
            agent_id=ctx.agent.id,
            session_id=ctx.session.id
        )

    # Monitor tool response formats
    if ctx.tools_called:
        for tool_call in ctx.tools_called:
            vex.validate_tool_schema(tool_call.response, ctx.agent.tools)

    # Session embedding freshness
    if 'embeddings_cache' in ctx.session:
        vex.check_cache_staleness(ctx.session['embeddings_cache'])

